import React, { useState, useCallback, useEffect } from 'react';
import { Mic, Send, Square, Loader2, AlertCircle } from 'lucide-react';
import { useGeminiLive } from '../hooks/useGeminiLive.ts';
import { GeminiLiveStatus } from '../types.ts';

interface ChatInputProps {
  onSendMessage: (text: string) => void;
  onSendVoiceMessage: (userText: string, aiText: string) => void;
  isLoading: boolean;
  systemInstruction: string;
}

const MicButton: React.FC<{ status: GeminiLiveStatus; onClick: () => void }> = ({ status, onClick }) => {
    // Helper to determine button styling based on status
    const getButtonContent = () => {
        switch (status) {
            case GeminiLiveStatus.CONNECTING:
                return (
                    <div className="flex items-center justify-center w-11 h-11 rounded-full bg-gray-100 dark:bg-gray-800 border-2 border-brand-blue/30 cursor-wait">
                        <Loader2 size={20} className="text-brand-blue animate-spin" />
                    </div>
                );
            case GeminiLiveStatus.LISTENING:
                return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-red-500 hover:bg-red-600 text-white shadow-[0_0_15px_rgba(239,68,68,0.5)] ring-4 ring-red-500/20 animate-pulse transition-all duration-300"
                        title="Stop Listening"
                    >
                        <Square size={18} className="fill-current" />
                    </button>
                );
            case GeminiLiveStatus.ERROR:
                 return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-red-600 hover:bg-red-700 text-white shadow-lg transition-all duration-300"
                        title="Retry Connection"
                    >
                        <AlertCircle size={20} />
                    </button>
                );
            default: // IDLE
                return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-brand-blue hover:bg-brand-blue/90 text-white shadow-lg shadow-brand-blue/30 hover:scale-105 transition-all duration-300"
                        title="Start Voice Chat"
                    >
                        <Mic size={20} />
                    </button>
                );
        }
    };

    return getButtonContent();
};


export const ChatInput: React.FC<ChatInputProps> = ({ onSendMessage, onSendVoiceMessage, isLoading, systemInstruction }) => {
  const [inputText, setInputText] = useState('');
  const { status, userTranscript, aiTranscript, startSession, stopSession, error } = useGeminiLive();

  useEffect(() => {
    if (status === GeminiLiveStatus.LISTENING) {
      setInputText(userTranscript);
    }
  }, [userTranscript, status]);

  const handleSend = () => {
    if (inputText.trim() && !isLoading) {
      onSendMessage(inputText.trim());
      setInputText('');
    }
  };

  const handleMicToggle = useCallback(() => {
    if (status === GeminiLiveStatus.IDLE || status === GeminiLiveStatus.ERROR) {
      startSession({
        onTurnComplete: (finalUserTranscript, finalAiTranscript) => {
          onSendVoiceMessage(finalUserTranscript, finalAiTranscript);
          setInputText('');
        },
        systemInstruction
      });
    } else {
      stopSession();
    }
  }, [status, startSession, stopSession, onSendVoiceMessage, systemInstruction]);

  const isInputDisabled = isLoading || status === GeminiLiveStatus.LISTENING || status === GeminiLiveStatus.CONNECTING;

  return (
    <div className="p-4 bg-white/5 dark:bg-gray-800/20 backdrop-blur-lg border-t border-white/10 dark:border-gray-700/50">
        {error && <div className="mb-2 text-center text-red-500 text-sm animate-fade-in">{error}</div>}
        <div className="flex items-end gap-3 max-w-4xl mx-auto">
            <div className="flex-1 relative">
                <textarea
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    onKeyDown={(e) => {
                        if (e.key === 'Enter' && !e.shiftKey) {
                            e.preventDefault();
                            handleSend();
                        }
                    }}
                    placeholder={status === GeminiLiveStatus.LISTENING ? "Listening..." : "Type a message..."}
                    className="w-full p-3 pr-10 rounded-2xl bg-white dark:bg-gray-700/50 border border-gray-200 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-brand-blue/50 focus:border-brand-blue resize-none min-h-[48px] max-h-32 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm"
                    rows={1}
                    disabled={isInputDisabled}
                />
            </div>

            <MicButton status={status} onClick={handleMicToggle} />

            <button
                onClick={handleSend}
                disabled={!inputText.trim() || isInputDisabled}
                className="flex items-center justify-center w-11 h-11 rounded-full bg-brand-blue text-white hover:bg-brand-blue/90 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200 shadow-lg shadow-brand-blue/20 hover:scale-105"
            >
                {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Send size={20} className="ml-0.5" />}
            </button>
        </div>
        {status === GeminiLiveStatus.LISTENING && aiTranscript && (
             <div className="mt-2 text-center text-xs text-gray-500 dark:text-gray-400 animate-pulse truncate">
                 AI: {aiTranscript}
             </div>
        )}
    </div>
  );
};

import { useState, useRef, useCallback } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';
import type { LiveServerMessage, Blob } from '@google/genai';
import { encode, decode, decodeAudioData } from '../utils/audio.ts';
import { GeminiLiveStatus } from '../types.ts';

interface StartSessionOptions {
  onTurnComplete: (userTranscript: string, aiTranscript: string) => void;
  systemInstruction: string;
}

export const useGeminiLive = () => {
  const [status, setStatus] = useState<GeminiLiveStatus>(GeminiLiveStatus.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [userTranscript, setUserTranscript] = useState('');
  const [aiTranscript, setAiTranscript] = useState('');

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const onTurnCompleteCallbackRef = useRef<((user: string, ai: string) => void) | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef(0);

  const sourcesRef = useRef(new Set<AudioBufferSourceNode>());

  const currentInputTranscriptionRef = useRef('');
  const currentOutputTranscriptionRef = useRef('');

  const cleanup = useCallback(() => {
    if (sourcesRef.current) {
        for (const source of sourcesRef.current.values()) {
            source.stop(0);
        }
        sourcesRef.current.clear();
    }

    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }
    if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
      inputAudioContextRef.current.close();
    }
    if (outputAudioContextRef.current && outputAudioContextRef.current.state !== 'closed') {
      outputAudioContextRef.current.close();
    }
    sessionPromiseRef.current?.then(session => session.close()).catch(console.error);
    sessionPromiseRef.current = null;
  }, []);

  const stopSession = useCallback(() => {
    cleanup();
    setStatus(GeminiLiveStatus.IDLE);
    setUserTranscript('');
    setAiTranscript('');
    setError(null);
  }, [cleanup]);

  const startSession = useCallback(async ({ onTurnComplete, systemInstruction }: StartSessionOptions) => {
    setStatus(GeminiLiveStatus.CONNECTING);
    setError(null);
    setUserTranscript('');
    setAiTranscript('');
    currentInputTranscriptionRef.current = '';
    currentOutputTranscriptionRef.current = '';
    onTurnCompleteCallbackRef.current = onTurnComplete;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
      inputAudioContextRef.current = new AudioContextClass({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContextClass({ sampleRate: 24000 });
      nextStartTimeRef.current = 0;

      // Strictly obtain API key from environment variable as per guidelines.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      sessionPromiseRef.current = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            if (!inputAudioContextRef.current) return;
            const source = inputAudioContextRef.current.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            function createBlob(data: Float32Array): Blob {
              const l = data.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = data[i] * 32768;
              }
              return {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
            }

            scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
              const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);
              sessionPromiseRef.current?.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContextRef.current.destination);
            setStatus(GeminiLiveStatus.LISTENING);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
                currentOutputTranscriptionRef.current += message.serverContent.outputTranscription.text;
                setAiTranscript(currentOutputTranscriptionRef.current);
            } 
            if (message.serverContent?.inputTranscription) {
                currentInputTranscriptionRef.current += message.serverContent.inputTranscription.text;
                setUserTranscript(currentInputTranscriptionRef.current);
            }
            if (message.serverContent?.turnComplete) {
                if (onTurnCompleteCallbackRef.current) {
                  onTurnCompleteCallbackRef.current(currentInputTranscriptionRef.current, currentOutputTranscriptionRef.current);
                }
                currentInputTranscriptionRef.current = '';
                currentOutputTranscriptionRef.current = '';
                setUserTranscript('');
                setAiTranscript('');
            }

            const base64EncodedAudioString = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64EncodedAudioString && outputAudioContextRef.current) {
                const audioBytes = decode(base64EncodedAudioString);
                const audioBuffer = await decodeAudioData(audioBytes, outputAudioContextRef.current, 24000, 1);

                const source = outputAudioContextRef.current.createBufferSource();
                source.buffer = audioBuffer;
                source.connect(outputAudioContextRef.current.destination);

                source.addEventListener('ended', () => {
                    sourcesRef.current.delete(source);
                });

                const currentTime = outputAudioContextRef.current.currentTime;
                const startTime = Math.max(currentTime, nextStartTimeRef.current);

                source.start(startTime);
                nextStartTimeRef.current = startTime + audioBuffer.duration;
                sourcesRef.current.add(source);
            }

            const interrupted = message.serverContent?.interrupted;
            if (interrupted) {
                for (const source of sourcesRef.current.values()) {
                    source.stop(0);
                    sourcesRef.current.delete(source);
                }
                nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: ErrorEvent) => {
            console.error('Gemini Live API Error:', e);
            setError('Connection error. Please try again.');
            setStatus(GeminiLiveStatus.ERROR);
            cleanup();
          },
          onclose: (e: CloseEvent) => {
            stopSession();
          },
        },
        config: {
          systemInstruction: systemInstruction,
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
        },
      });
      await sessionPromiseRef.current;
    } catch (err: any) {
      console.error('Failed to start session:', err);
      setError('Could not access microphone or connection failed.');
      setStatus(GeminiLiveStatus.ERROR);
      cleanup();
    }
  }, [cleanup, stopSession]);

  return { status, error, userTranscript, aiTranscript, startSession, stopSession };
};

import type { User, Conversation } from '../types.ts';

const isLocal = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1';
const API_BASE_URL = isLocal ? 'http://localhost:8000/api' : `${window.location.protocol}//${window.location.host}/api`;

const getAuthToken = (): string | null => {
    try {
        const item = localStorage.getItem('easit-jwt');
        return item ? JSON.parse(item) : null;
    } catch (e) {
        return null;
    }
};

const handleResponse = async (response: Response) => {
    if (!response.ok) {
        let errorMessage = `Request failed with status ${response.status}`;
        try {
            const errorData = await response.json();
            if (errorData && errorData.detail) {
                errorMessage = errorData.detail;
            } else if (errorData && errorData.message) {
                 errorMessage = errorData.message;
            }
        } catch (e) {}
        throw new Error(errorMessage);
    }
    return response.json();
};

const safeFetch = async (url: string, options: RequestInit) => {
    try {
        const response = await fetch(url, options);
        return await handleResponse(response);
    } catch (error: any) {
        if (url.includes('/auth/login') || url.includes('/auth/signup') || url.includes('/auth/google')) {
             return {
                token: 'guest-demo-token',
                user: {
                    name: 'Offline User',
                    email: 'guest@solveearn.com',
                    picture: undefined
                }
            };
        }
        if (url.includes('/conversations')) {
            return [
                 {
                     id: 'offline-conv-1',
                     title: 'Welcome (Offline Mode)',
                     messages: [
                         {
                             id: 'msg-1',
                             role: 'model',
                             text: 'The backend server is unreachable. You are currently in offline mode.\n\nYou can still chat with me using the Gemini API directly!',
                             timestamp: new Date().toISOString()
                         }
                     ],
                     createdAt: new Date().toISOString()
                 }
            ];
        }
        throw new Error('Cannot connect to server.');
    }
};

const apiService = {
    async googleAuth(credential: string): Promise<{ token: string; user: User }> {
        return safeFetch(`${API_BASE_URL}/auth/google`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ credential }),
        });
    },
    async login(email: string, password: string): Promise<{ token: string; user: User }> {
        return safeFetch(`${API_BASE_URL}/auth/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ email, password }),
        });
    },
    async signup(name: string, email: string, password: string): Promise<{ token: string; user: User }> {
        return safeFetch(`${API_BASE_URL}/auth/signup`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name, email, password }),
        });
    },
    async getConversations(): Promise<Conversation[]> {
        const token = getAuthToken();
        if (!token) return [];
        if (token === 'guest-demo-token') {
             try {
                 const localData = localStorage.getItem('easit-guest-conversations');
                 if (localData) return JSON.parse(localData);
             } catch (e) {}
             return [];
        }
        return safeFetch(`${API_BASE_URL}/conversations`, {
            headers: { 'Authorization': `Bearer ${token}` },
        });
    },
};

export default apiService;

import type { Message, ConnectionStatus } from '../types.ts';

const isLocal = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1';
const wsProtocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
const WEBSOCKET_URL = isLocal ? 'ws://localhost:8000/ws' : `${wsProtocol}//${window.location.host}/ws`;

type Listener<T> = (data: T) => void;

class WebSocketService {
    private ws: WebSocket | null = null;
    private messageListeners: Listener<any>[] = [];
    private statusListeners: Listener<ConnectionStatus>[] = [];
    private reconnectTimeout: any = null;
    private reconnectAttempts = 0;
    private maxReconnectDelay = 30000;
    private token: string | null = null;
    public status: ConnectionStatus = 'disconnected';

    connect(token: string) {
        this.token = token;
        if (this.ws && (this.ws.readyState === WebSocket.OPEN || this.ws.readyState === WebSocket.CONNECTING)) return;

        this.updateStatus('connecting');
        try {
            this.ws = new WebSocket(WEBSOCKET_URL);
            this.ws.onopen = () => {
                this.updateStatus('connected');
                this.reconnectAttempts = 0;
                this.ws?.send(JSON.stringify({ type: 'auth', payload: { token } }));
            };
            this.ws.onmessage = (event) => {
                try {
                    const data = JSON.parse(event.data);
                    this.messageListeners.forEach(listener => listener(data));
                } catch (e) {}
            };
            this.ws.onclose = () => {
                this.ws = null;
                if (this.status !== 'disconnected') this.attemptReconnect();
            };
            this.ws.onerror = () => {};
        } catch (e) {
            this.updateStatus('disconnected');
        }
    }

    private attemptReconnect() {
        this.updateStatus('reconnecting');
        const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts), this.maxReconnectDelay);
        this.reconnectAttempts++;
        if (this.reconnectTimeout) clearTimeout(this.reconnectTimeout);
        this.reconnectTimeout = setTimeout(() => {
            if (this.token) this.connect(this.token);
        }, delay);
    }

    disconnect() {
        this.updateStatus('disconnected');
        this.token = null;
        if (this.reconnectTimeout) {
            clearTimeout(this.reconnectTimeout);
            this.reconnectTimeout = null;
        }
        if (this.ws) {
            this.ws.close();
            this.ws = null;
        }
    }

    private updateStatus(newStatus: ConnectionStatus) {
        this.status = newStatus;
        this.statusListeners.forEach(listener => listener(newStatus));
    }

    sendMessage(type: string, payload: any) {
        if (this.ws && this.ws.readyState === WebSocket.OPEN) {
            this.ws.send(JSON.stringify({ type, payload }));
        } else {
            throw new Error('Not connected to server');
        }
    }

    addMessageListener(callback: Listener<any>) { this.messageListeners.push(callback); }
    removeMessageListener(callback: Listener<any>) { this.messageListeners = this.messageListeners.filter(cb => cb !== callback); }
    addStatusListener(callback: Listener<ConnectionStatus>) {
        this.statusListeners.push(callback);
        callback(this.status);
    }
    removeStatusListener(callback: Listener<ConnectionStatus>) { this.statusListeners = this.statusListeners.filter(cb => cb !== callback); }
}

export const websocketService = new WebSocketService();

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { Sidebar } from './components/Sidebar.tsx';
import { ChatView } from './components/ChatView.tsx';
import { TopBar } from './components/TopBar.tsx';
import { Modal } from './components/Modal.tsx';
import { SettingsModal } from './components/SettingsModal.tsx';
import { ToastContainer, type ToastMessage, type ToastType } from './components/Toast.tsx';
import type { Conversation, Message, User, PersonaSettings, ConnectionStatus } from './types.ts';
import { useLocalStorage } from './hooks/useLocalStorage.ts';
import { WelcomeScreen } from './components/WelcomeScreen.tsx';
import apiService from './services/apiService.ts';
import { websocketService } from './services/websocketService.ts';
import { GoogleGenAI } from "@google/genai";

interface ChatAppProps {
  user: User;
  onSignOut: () => void;
}

const DEFAULT_PERSONA: PersonaSettings = {
    tone: 'friendly',
    verbosity: 'balanced',
    style: 'casual'
};

const ChatApp: React.FC<ChatAppProps> = ({ user, onSignOut }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [personaSettings, setPersonaSettings] = useLocalStorage<PersonaSettings>('easit-persona', DEFAULT_PERSONA);

  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [activeModal, setActiveModal] = useState<string | null>(null);
  const [isSettingsModalVisible, setSettingsModalVisible] = useState(false);

  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>('disconnected');

  const addToast = useCallback((message: string, type: ToastType) => {
    const id = Date.now().toString() + Math.random();
    setToasts(prev => [...prev, { id, message, type }]);
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const systemInstruction = useMemo(() => {
      const toneMap: Record<string, string> = {
        friendly: "Be warm, encouraging, and use a conversational tone with occasional emojis.",
        professional: "Be formal, objective, and maintain a respectful distance. Avoid emojis.",
        humorous: "Be witty, playful, and include lighthearted jokes where appropriate.",
        empathetic: "Be understanding, validate the user's feelings, and offer supportive language."
      };

      const verbosityMap: Record<string, string> = {
        concise: "Keep responses extremely brief and directly to the point. No fluff.",
        balanced: "Provide moderate detail, explaining key concepts clearly without over-explaining.",
        detailed: "Provide comprehensive, in-depth responses covering background, examples, and edge cases."
      };

      const styleMap: Record<string, string> = {
        casual: "Use relaxed language, contractions (e.g., 'don't', 'can't'), and simple terms.",
        formal: "Use standard, grammatically rigorous English. Avoid contractions and slang.",
        technical: "Use precise technical terminology. Assume the user is an expert developer."
      };

      return `You are Easit.ai, an intelligent assistant for the SolveEarn community.

      Follow these PERSONA INSTRUCTIONS strictly:
      1. TONE: ${toneMap[personaSettings.tone] || toneMap.friendly}
      2. VERBOSITY: ${verbosityMap[personaSettings.verbosity] || verbosityMap.balanced}
      3. STYLE: ${styleMap[personaSettings.style] || styleMap.casual}

      Always prioritize the user's request while maintaining this persona.`;
  }, [personaSettings]);

  useEffect(() => {
      const handleStatusChange = (status: ConnectionStatus) => {
          setConnectionStatus(status);
      };

      websocketService.addStatusListener(handleStatusChange);
      return () => {
          websocketService.removeStatusListener(handleStatusChange);
      };
  }, []);

  const loadConversations = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
        const storedConversations = await apiService.getConversations();
        setConversations(storedConversations);
    } catch (err: any) {
        console.error("Failed to load conversations:", err);
        setError("Failed to load your conversations.");
        addToast(err.message || "Failed to load conversations", 'error');
    } finally {
        setIsLoading(false);
    }
  }, [addToast]);

  useEffect(() => {
    loadConversations();
  }, [loadConversations]);

  useEffect(() => {
      if (!isLoading && user.email === 'guest@solveearn.com') {
          localStorage.setItem('easit-guest-conversations', JSON.stringify(conversations));
      }
  }, [conversations, user, isLoading]);

  const handleAiMessage = useCallback((data: any) => {
    if (data.type === 'aiMessage') {
        const { conversationId, message } = data.payload;
        setConversations(prev => {
            return prev.map(c => {
                if (c.id === conversationId) {
                    return { ...c, messages: [...c.messages, message] };
                }
                return c;
            });
        });
    } else if (data.type === 'error') {
        addToast(data.payload.message || 'An error occurred', 'error');
    }
  }, [addToast]);

  useEffect(() => {
      websocketService.addMessageListener(handleAiMessage);
      return () => {
          websocketService.removeMessageListener(handleAiMessage);
      };
  }, [handleAiMessage]);


  const activeConversation = useMemo(() => {
    return conversations.find(c => c.id === activeConversationId) || null;
  }, [conversations, activeConversationId]);

  const handleNewConversation = useCallback(() => {
    const newConversation: Conversation = {
      id: `conv-${Date.now()}`,
      title: 'New Chat',
      messages: [],
      createdAt: new Date().toISOString(),
    };
    setConversations(prev => [newConversation, ...prev]);
    setActiveConversationId(newConversation.id);
    setIsMobileSidebarOpen(false);
  }, []);

  const handleSelectConversation = useCallback((id: string) => {
    setActiveConversationId(id);
    setIsMobileSidebarOpen(false);
  }, []);

  const addMessageToConversation = useCallback(async (conversationId: string, message: Message) => {
    setConversations(prev => prev.map(c => {
        if (c.id === conversationId) {
            return { ...c, messages: [...c.messages, message] };
        }
        return c;
    }));

    const token = localStorage.getItem('easit-jwt');
    const isGuest = token && token.includes('guest-demo-token');

    if (isGuest && message.role === 'user') {
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: message.text,
                config: {
                    systemInstruction: systemInstruction
                }
            });
            const text = response.text;
            if (text) {
                 const aiMessage: Message = {
                    id: `ai-${Date.now()}`,
                    role: 'model',
                    text: text,
                    timestamp: new Date().toISOString()
                };
                setConversations(prev => prev.map(c => 
                    c.id === conversationId ? { ...c, messages: [...c.messages, aiMessage] } : c
                ));
            }
        } catch (e: any) {
            console.error("Gemini Error", e);
            let errorMessageText = "I'm having trouble connecting right now.";
            addToast("Failed to generate response: " + e.message, 'error');

             const errorMessage: Message = {
                id: `err-${Date.now()}`,
                role: 'model',
                text: errorMessageText,
                timestamp: new Date().toISOString()
            };
             setConversations(prev => prev.map(c => 
                c.id === conversationId ? { ...c, messages: [...c.messages, errorMessage] } : c
            ));
        }
    } else if (!isGuest) {
        try {
            websocketService.sendMessage('chatMessage', { conversationId, userMessage: message, systemInstruction });
        } catch (e: any) {
             addToast("Connection error: Message not sent.", 'error');
        }
    }
  }, [systemInstruction, addToast]);

  const handleSaveConversation = useCallback(() => {
    if (!activeConversation) {
        addToast('No active conversation to save', 'info');
        return;
    }
    try {
        const title = activeConversation.title || 'Conversation';
        const date = new Date(activeConversation.createdAt).toLocaleDateString();
        let content = `Title: ${title}\nDate: ${date}\n\n`;
        activeConversation.messages.forEach(msg => {
            const role = msg.role === 'user' ? 'You' : 'Easit.ai';
            const time = new Date(msg.timestamp).toLocaleTimeString();
            content += `[${time}] ${role}:\n${msg.text}\n\n`;
        });
        const blob = new Blob([content], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${title.replace(/\s+/g, '_').toLowerCase()}_transcript.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        addToast('Conversation saved successfully', 'success');
    } catch (e) {
        addToast('Failed to save conversation', 'error');
    }
  }, [activeConversation, addToast]);

  const getModalContent = (modalTitle: string) => {
      switch (modalTitle.toLowerCase()) {
          case 'about': return <p>Easit.ai is a modern, conversational AI assistant with a sleek interface.</p>;
          case 'privacy': return <p>Your privacy is important. Conversations are now securely stored in your account.</p>;
          case 'contact us': return <p>Contact us at <a href="mailto:support@easit.ai" className="text-brand-blue hover:underline">support@easit.ai</a>.</p>;
          case 'account': return <p>You are signed in as {user.email}.</p>;
          default: return <p>Content not available.</p>;
      }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex items-center justify-center h-full">
          <div className="w-8 h-8 border-4 border-t-transparent border-brand-blue rounded-full animate-spin"></div>
        </div>
      );
    }
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-center p-4">
          <p className="text-red-500 mb-4">{error}</p>
          <button onClick={loadConversations} className="bg-brand-blue text-white px-4 py-2 rounded-lg font-semibold hover:bg-brand-blue/90 transition-colors">Retry</button>
        </div>
      );
    }
    if (activeConversation) {
      return <ChatView key={activeConversation.id} conversation={activeConversation} addMessage={addMessageToConversation} systemInstruction={systemInstruction} />;
    }
    return <WelcomeScreen onNewConversation={handleNewConversation} />;
  };

  return (
    <div className="flex h-screen w-full bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans overflow-hidden">
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <Sidebar conversations={conversations} activeConversationId={activeConversationId} onSelectConversation={handleSelectConversation} onNewConversation={handleNewConversation} isMobileOpen={isMobileSidebarOpen} onClose={() => setIsMobileSidebarOpen(false)} />
      <main className="flex flex-1 flex-col transition-all duration-300 md:pl-64">
        <TopBar user={user} onSignOut={onSignOut} onToggleSidebar={() => setIsMobileSidebarOpen(true)} onShowModal={setActiveModal} onShowSettings={() => setSettingsModalVisible(true)} onSaveConversation={handleSaveConversation} conversationTitle={activeConversation?.title} connectionStatus={connectionStatus} />
        <div className="flex-1 overflow-hidden">{renderContent()}</div>
      </main>
      {isSettingsModalVisible && <SettingsModal settings={personaSettings} onUpdate={setPersonaSettings} onClose={() => setSettingsModalVisible(false)} />}
      {activeModal && <Modal title={activeModal} onClose={() => setActiveModal(null)}>{getModalContent(activeModal)}</Modal>}
    </div>
  );
};

export default ChatApp;

import React, { useState, useRef, useEffect } from 'react';
import { Sun, Moon, PanelLeft, LogOut, User as UserIcon, Settings, Info, Shield, Mail, Sliders, WifiOff, RefreshCw, Save } from 'lucide-react';
import { useTheme } from '../hooks/useTheme.ts';
import type { User, ConnectionStatus } from '../types.ts';

interface TopBarProps {
    user: User;
    onSignOut: () => void;
    onToggleSidebar: () => void;
    onShowModal: (modal: string) => void;
    onShowSettings: () => void;
    onSaveConversation: () => void;
    conversationTitle?: string;
    connectionStatus: ConnectionStatus;
}

const UserMenu: React.FC<{ user: User; onSignOut: () => void; onShowModal: (modal: string) => void; onShowSettings: () => void; }> = ({ user, onSignOut, onShowModal, onShowSettings }) => {
    const [isOpen, setIsOpen] = useState(false);
    const menuRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const menuItems = [
        { label: 'Customize Persona', icon: Sliders, onClick: () => onShowSettings() },
        { label: 'Account', icon: Settings, onClick: () => onShowModal('Account') },
        { label: 'About', icon: Info, onClick: () => onShowModal('About') },
        { label: 'Privacy', icon: Shield, onClick: () => onShowModal('Privacy') },
        { label: 'Contact Us', icon: Mail, onClick: () => onShowModal('Contact Us') },
    ];

    return (
        <div className="relative" ref={menuRef}>
            <button onClick={() => setIsOpen(!isOpen)} className="w-9 h-9 rounded-full focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-blue focus:ring-offset-gray-800">
                {user.picture ? (
                    <img src={user.picture} alt="User" className="w-full h-full rounded-full" />
                ) : (
                    <div className="w-full h-full rounded-full bg-brand-purple flex items-center justify-center">
                        <UserIcon size={20} className="text-white" />
                    </div>
                )}
            </button>
            {isOpen && (
                <div className="absolute right-0 mt-2 w-64 bg-white dark:bg-gray-800 rounded-md shadow-lg py-1 z-20 border border-white/10 dark:border-gray-700/50">
                    <div className="px-4 py-2 border-b border-gray-200 dark:border-gray-700">
                        <p className="text-sm font-semibold text-gray-800 dark:text-white truncate">{user.name}</p>
                        <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{user.email}</p>
                    </div>
                    <div className="py-1">
                        {menuItems.map((item, index) => (
                             <button
                                key={index}
                                onClick={() => { item.onClick(); setIsOpen(false); }}
                                className="w-full text-left flex items-center gap-3 px-4 py-2 text-sm text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-700"
                            >
                                <item.icon size={16} />
                                {item.label}
                            </button>
                        ))}
                    </div>
                    <div className="py-1 border-t border-gray-200 dark:border-gray-700">
                         <button
                            onClick={onSignOut}
                            className="w-full text-left flex items-center gap-3 px-4 py-2 text-sm text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-500/10"
                        >
                            <LogOut size={16} />
                            Sign Out
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

const ConnectionBadge: React.FC<{ status: ConnectionStatus }> = ({ status }) => {
    if (status === 'connected') return null;

    if (status === 'reconnecting') {
        return (
            <div className="flex items-center gap-1.5 px-2 py-1 bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400 text-xs rounded-full animate-pulse">
                <RefreshCw size={12} className="animate-spin" />
                <span className="hidden md:inline">Reconnecting...</span>
            </div>
        );
    }

    if (status === 'disconnected') {
        return (
            <div className="flex items-center gap-1.5 px-2 py-1 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 text-xs rounded-full">
                <WifiOff size={12} />
                <span className="hidden md:inline">Offline</span>
            </div>
        );
    }

    return null;
};


export const TopBar: React.FC<TopBarProps> = ({ user, onSignOut, onToggleSidebar, onShowModal, conversationTitle, onShowSettings, onSaveConversation, connectionStatus }) => {
  const { theme, toggleTheme } = useTheme();

  return (
    <header className="flex-shrink-0 h-16 flex items-center justify-between px-6 bg-white/5 dark:bg-gray-800/20 backdrop-blur-lg border-b border-white/10 dark:border-gray-700/50">
      <div className="flex items-center gap-2">
        <button
          onClick={onToggleSidebar}
          className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors md:hidden"
          aria-label="Toggle sidebar"
        >
          <PanelLeft size={20} />
        </button>
        <h2 className="text-lg font-semibold truncate max-w-[calc(100%-4rem)] md:max-w-xs">{conversationTitle || 'Easit.ai'}</h2>
        <ConnectionBadge status={connectionStatus} />
      </div>
      <div className="flex items-center gap-3">
        <button
          onClick={onSaveConversation}
          className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
          aria-label="Save conversation"
          title="Save Conversation"
        >
            <Save size={20} />
        </button>
        <button
          onClick={toggleTheme}
          className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
          aria-label={`Switch to ${theme === 'dark' ? 'light' : 'dark'} mode`}
        >
          {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
        </button>
        <UserMenu user={user} onSignOut={onSignOut} onShowModal={onShowModal} onShowSettings={onShowSettings} />
      </div>
    </header>
  );
};

import React from 'react';
import { Modal } from './Modal.tsx';
import type { PersonaSettings } from '../types.ts';
import { MessageSquare, Volume2, PenTool, Check, RotateCcw } from 'lucide-react';

interface SettingsModalProps {
  settings: PersonaSettings;
  onUpdate: (settings: PersonaSettings) => void;
  onClose: () => void;
}

interface OptionGroupProps {
  label: string;
  icon: React.ElementType;
  value: string;
  options: string[];
  onChange: (val: any) => void;
}

function OptionGroup({ 
  label, 
  icon: Icon, 
  value, 
  options, 
  onChange 
}: OptionGroupProps) {
  return (
    <div className="mb-6">
      <div className="flex items-center gap-2 mb-3 text-gray-700 dark:text-gray-200 font-semibold">
        <Icon size={18} />
        <span>{label}</span>
      </div>
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
        {options.map((opt) => (
          <button
            key={opt}
            onClick={() => onChange(opt)}
            className={`
              relative px-3 py-2 rounded-lg text-sm capitalize transition-all duration-200 border
              ${value === opt 
                ? 'bg-brand-blue/10 border-brand-blue text-brand-blue dark:text-brand-purple dark:border-brand-purple dark:bg-brand-purple/10' 
                : 'bg-gray-100 dark:bg-gray-700/50 border-transparent text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700'}
            `}
          >
            {opt}
            {value === opt && (
              <div className="absolute top-1 right-1">
                <Check size={12} strokeWidth={3} />
              </div>
            )}
          </button>
        ))}
      </div>
    </div>
  );
}

export function SettingsModal({ settings, onUpdate, onClose }: SettingsModalProps) {
  const updateSetting = (key: keyof PersonaSettings, value: any) => {
    onUpdate({ ...settings, [key]: value });
  };

  const handleReset = () => {
      onUpdate({
          tone: 'friendly',
          verbosity: 'balanced',
          style: 'casual'
      });
  };

  return (
    <Modal title="Settings" onClose={onClose}>
      <div className="p-1 max-h-[70vh] overflow-y-auto">
        <p className="text-sm text-gray-500 dark:text-gray-400 mb-6">
          Adjust how Easit.ai speaks and behaves to better suit your needs. Changes are applied instantly to new messages.
        </p>

        <OptionGroup
          label="Tone"
          icon={Volume2}
          value={settings.tone}
          options={['friendly', 'professional', 'humorous', 'empathetic']}
          onChange={(val) => updateSetting('tone', val)}
        />

        <OptionGroup
          label="Verbosity"
          icon={MessageSquare}
          value={settings.verbosity}
          options={['concise', 'balanced', 'detailed']}
          onChange={(val) => updateSetting('verbosity', val)}
        />

        <OptionGroup
          label="Style"
          icon={PenTool}
          value={settings.style}
          options={['casual', 'formal', 'technical']}
          onChange={(val) => updateSetting('style', val)}
        />

        <div className="mt-8 pt-4 border-t border-gray-200 dark:border-gray-700 flex justify-between items-center">
            <button
                onClick={handleReset}
                className="flex items-center gap-2 text-sm text-gray-500 hover:text-brand-blue transition-colors"
            >
                <RotateCcw size={14} />
                Reset Defaults
            </button>
            <button 
                onClick={onClose}
                className="px-6 py-2 bg-brand-blue text-white rounded-full font-medium hover:bg-brand-blue/90 transition-colors"
            >
                Done
            </button>
        </div>
      </div>
    </Modal>
  );
}

import React from 'react';
import { Modal } from './Modal.tsx';
import type { Todo } from '../types.ts';
import { Trash2, Circle, CheckCircle2 } from 'lucide-react';

interface TodoModalProps {
  todos: Todo[];
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
  onClose: () => void;
}

export const TodoModal: React.FC<TodoModalProps> = ({ todos, onToggle, onDelete, onClose }) => {
  const pendingTodos = todos.filter(t => !t.completed);
  const completedTodos = todos.filter(t => t.completed);

  return (
    <Modal title="My To-Do List" onClose={onClose}>
      <div className="space-y-4 max-h-[60vh] overflow-y-auto pr-2">
        {todos.length === 0 ? (
          <p className="text-center text-gray-500 dark:text-gray-400 py-4">Your to-do list is empty. Add tasks by talking to the assistant!</p>
        ) : (
          <>
            {pendingTodos.length > 0 && (
              <div>
                <h3 className="text-sm font-semibold text-gray-500 dark:text-gray-400 mb-2">To-Do</h3>
                <ul className="space-y-2">
                  {pendingTodos.map(todo => (
                    <li key={todo.id} className="flex items-center justify-between p-2 rounded-lg bg-gray-100 dark:bg-gray-700/50">
                      <button onClick={() => onToggle(todo.id)} className="flex items-center gap-3 flex-1 text-left">
                        <Circle size={20} className="text-gray-400" />
                        <span>{todo.text}</span>
                      </button>
                      <button onClick={() => onDelete(todo.id)} className="p-1 text-gray-400 hover:text-red-500 transition-colors" aria-label={`Delete task: ${todo.text}`}>
                        <Trash2 size={16} />
                      </button>
                    </li>
                  ))}
                </ul>
              </div>
            )}
            {completedTodos.length > 0 && (
              <div>
                <h3 className="text-sm font-semibold text-gray-500 dark:text-gray-400 mb-2 mt-4">Completed</h3>
                <ul className="space-y-2">
                  {completedTodos.map(todo => (
                    <li key={todo.id} className="flex items-center justify-between p-2 rounded-lg bg-gray-100 dark:bg-gray-700/50 opacity-60">
                      <button onClick={() => onToggle(todo.id)} className="flex items-center gap-3 flex-1 text-left">
                        <CheckCircle2 size={20} className="text-green-500" />
                        <span className="line-through">{todo.text}</span>
                      </button>
                       <button onClick={() => onDelete(todo.id)} className="p-1 text-gray-400 hover:text-red-500 transition-colors" aria-label={`Delete task: ${todo.text}`}>
                        <Trash2 size={16} />
                      </button>
                    </li>
                  ))}
                </ul>
              </div>
            )}
          </>
        )}
      </div>
    </Modal>
  );
};

import { useState, useEffect, useCallback } from 'react';
import type { Theme } from '../types.ts';

export const useTheme = () => {
  const [theme, setTheme] = useState<Theme>('dark');

  useEffect(() => {
    const storedTheme = localStorage.getItem('easit-theme') as Theme | null;
    const preferredTheme = window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    const initialTheme = storedTheme || preferredTheme;
    setTheme(initialTheme);
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('easit-theme', theme);
  }, [theme]);

  const toggleTheme = useCallback(() => {
    setTheme((prevTheme) => (prevTheme === 'light' ? 'dark' : 'light'));
  }, []);

  return { theme, toggleTheme };
};

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { Sidebar } from './components/Sidebar.tsx';
import { ChatView } from './components/ChatView.tsx';
import { TopBar } from './components/TopBar.tsx';
import { Modal } from './components/Modal.tsx';
import { SettingsModal } from './components/SettingsModal.tsx';
import { ToastContainer, type ToastMessage, type ToastType } from './components/Toast.tsx';
import type { Conversation, Message, User, PersonaSettings, ConnectionStatus, Source } from './types.ts';
import { useLocalStorage } from './hooks/useLocalStorage.ts';
import { WelcomeScreen } from './components/WelcomeScreen.tsx';
import apiService from './services/apiService.ts';
import { websocketService } from './services/websocketService.ts';
import { GoogleGenAI } from "@google/genai";

interface ChatAppProps {
  user: User;
  onSignOut: () => void;
}

const DEFAULT_PERSONA: PersonaSettings = {
    tone: 'friendly',
    verbosity: 'balanced',
    style: 'casual'
};

const ChatApp: React.FC<ChatAppProps> = ({ user, onSignOut }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [personaSettings, setPersonaSettings] = useLocalStorage<PersonaSettings>('easit-persona', DEFAULT_PERSONA);
  const [isSearchActive, setIsSearchActive] = useState(false);

  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [activeModal, setActiveModal] = useState<string | null>(null);
  const [isSettingsModalVisible, setSettingsModalVisible] = useState(false);

  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>('disconnected');

  const addToast = useCallback((message: string, type: ToastType) => {
    const id = Date.now().toString() + Math.random();
    setToasts(prev => [...prev, { id, message, type }]);
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const systemInstruction = useMemo(() => {
      const toneMap: Record<string, string> = {
        friendly: "Be warm, encouraging, and use a conversational tone with occasional emojis.",
        professional: "Be formal, objective, and maintain a respectful distance. Avoid emojis.",
        humorous: "Be witty, playful, and include lighthearted jokes where appropriate.",
        empathetic: "Be understanding, validate the user's feelings, and offer supportive language."
      };

      const verbosityMap: Record<string, string> = {
        concise: "Keep responses extremely brief and directly to the point. No fluff.",
        balanced: "Provide moderate detail, explaining key concepts clearly without over-explaining.",
        detailed: "Provide comprehensive, in-depth responses covering background, examples, and edge cases."
      };

      const styleMap: Record<string, string> = {
        casual: "Use relaxed language, contractions (e.g., 'don't', 'can't'), and simple terms.",
        formal: "Use standard, grammatically rigorous English. Avoid contractions and slang.",
        technical: "Use precise technical terminology. Assume the user is an expert developer."
      };

      return `You are Easit.ai, an intelligent assistant for the SolveEarn community.

      Follow these PERSONA INSTRUCTIONS strictly:
      1. TONE: ${toneMap[personaSettings.tone] || toneMap.friendly}
      2. VERBOSITY: ${verbosityMap[personaSettings.verbosity] || verbosityMap.balanced}
      3. STYLE: ${styleMap[personaSettings.style] || styleMap.casual}

      Always prioritize the user's request while maintaining this persona.`;
  }, [personaSettings]);

  useEffect(() => {
      const handleStatusChange = (status: ConnectionStatus) => {
          setConnectionStatus(status);
      };

      websocketService.addStatusListener(handleStatusChange);
      return () => {
          websocketService.removeStatusListener(handleStatusChange);
      };
  }, []);

  const loadConversations = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
        const storedConversations = await apiService.getConversations();
        setConversations(storedConversations);
    } catch (err: any) {
        console.error("Failed to load conversations:", err);
        setError("Failed to load your conversations.");
        addToast(err.message || "Failed to load conversations", 'error');
    } finally {
        setIsLoading(false);
    }
  }, [addToast]);

  useEffect(() => {
    loadConversations();
  }, [loadConversations]);

  useEffect(() => {
      if (!isLoading && user.email === 'guest@solveearn.com') {
          localStorage.setItem('easit-guest-conversations', JSON.stringify(conversations));
      }
  }, [conversations, user, isLoading]);

  const handleAiMessage = useCallback((data: any) => {
    if (data.type === 'aiMessage') {
        const { conversationId, message } = data.payload;
        setConversations(prev => {
            return prev.map(c => {
                if (c.id === conversationId) {
                    return { ...c, messages: [...c.messages, message] };
                }
                return c;
            });
        });
    } else if (data.type === 'error') {
        addToast(data.payload.message || 'An error occurred', 'error');
    }
  }, [addToast]);

  useEffect(() => {
      websocketService.addMessageListener(handleAiMessage);
      return () => {
          websocketService.removeMessageListener(handleAiMessage);
      };
  }, [handleAiMessage]);


  const activeConversation = useMemo(() => {
    return conversations.find(c => c.id === activeConversationId) || null;
  }, [conversations, activeConversationId]);

  const handleNewConversation = useCallback(() => {
    const newConversation: Conversation = {
      id: `conv-${Date.now()}`,
      title: 'New Chat',
      messages: [],
      createdAt: new Date().toISOString(),
    };
    setConversations(prev => [newConversation, ...prev]);
    setActiveConversationId(newConversation.id);
    setIsMobileSidebarOpen(false);
  }, []);

  const handleSelectConversation = useCallback((id: string) => {
    setActiveConversationId(id);
    setIsMobileSidebarOpen(false);
  }, []);

  const addMessageToConversation = useCallback(async (conversationId: string, message: Message) => {
    setConversations(prev => prev.map(c => {
        if (c.id === conversationId) {
            return { ...c, messages: [...c.messages, message] };
        }
        return c;
    }));

    const token = localStorage.getItem('easit-jwt');
    const isGuest = token && token.includes('guest-demo-token');

    if (isGuest && message.role === 'user') {
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Inclusion of search tool if active
            const config: any = {
                systemInstruction: systemInstruction,
            };
            if (isSearchActive) {
                config.tools = [{ googleSearch: {} }];
            }

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: message.text,
                config: config
            });

            const text = response.text;

            // Extract grounding metadata for hallucination-free verification
            const groundingMetadata: Source[] = [];
            if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
                response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                    if (chunk.web) {
                        groundingMetadata.push({
                            uri: chunk.web.uri,
                            title: chunk.web.title || chunk.web.uri
                        });
                    }
                });
            }

            if (text) {
                 const aiMessage: Message = {
                    id: `ai-${Date.now()}`,
                    role: 'model',
                    text: text,
                    timestamp: new Date().toISOString(),
                    groundingMetadata: groundingMetadata.length > 0 ? groundingMetadata : undefined
                };
                setConversations(prev => prev.map(c => 
                    c.id === conversationId ? { ...c, messages: [...c.messages, aiMessage] } : c
                ));
            }
        } catch (e: any) {
            console.error("Gemini Error", e);
            let errorMessageText = "I'm having trouble connecting right now.";
            addToast("Failed to generate response: " + e.message, 'error');

             const errorMessage: Message = {
                id: `err-${Date.now()}`,
                role: 'model',
                text: errorMessageText,
                timestamp: new Date().toISOString()
            };
             setConversations(prev => prev.map(c => 
                c.id === conversationId ? { ...c, messages: [...c.messages, errorMessage] } : c
            ));
        }
    } else if (!isGuest) {
        try {
            websocketService.sendMessage('chatMessage', { 
                conversationId, 
                userMessage: message, 
                systemInstruction,
                searchEnabled: isSearchActive 
            });
        } catch (e: any) {
             addToast("Connection error: Message not sent.", 'error');
        }
    }
  }, [systemInstruction, addToast, isSearchActive]);

  const handleSaveConversation = useCallback(() => {
    if (!activeConversation) {
        addToast('No active conversation to save', 'info');
        return;
    }
    try {
        const title = activeConversation.title || 'Conversation';
        const date = new Date(activeConversation.createdAt).toLocaleDateString();
        let content = `Title: ${title}\nDate: ${date}\n\n`;
        activeConversation.messages.forEach(msg => {
            const role = msg.role === 'user' ? 'You' : 'Easit.ai';
            const time = new Date(msg.timestamp).toLocaleTimeString();
            content += `[${time}] ${role}:\n${msg.text}\n\n`;
        });
        const blob = new Blob([content], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${title.replace(/\s+/g, '_').toLowerCase()}_transcript.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        addToast('Conversation saved successfully', 'success');
    } catch (e) {
        addToast('Failed to save conversation', 'error');
    }
  }, [activeConversation, addToast]);

  const getModalContent = (modalTitle: string) => {
      switch (modalTitle.toLowerCase()) {
          case 'about': return <p>Easit.ai is a modern, conversational AI assistant with a sleek interface.</p>;
          case 'privacy': return <p>Your privacy is important. Conversations are now securely stored in your account.</p>;
          case 'contact us': return <p>Contact us at <a href="mailto:support@easit.ai" className="text-brand-blue hover:underline">support@easit.ai</a>.</p>;
          case 'account': return <p>You are signed in as {user.email}.</p>;
          default: return <p>Content not available.</p>;
      }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex items-center justify-center h-full">
          <div className="w-8 h-8 border-4 border-t-transparent border-brand-blue rounded-full animate-spin"></div>
        </div>
      );
    }
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-center p-4">
          <p className="text-red-500 mb-4">{error}</p>
          <button onClick={loadConversations} className="bg-brand-blue text-white px-4 py-2 rounded-lg font-semibold hover:bg-brand-blue/90 transition-colors">Retry</button>
        </div>
      );
    }
    if (activeConversation) {
      return <ChatView 
        key={activeConversation.id} 
        conversation={activeConversation} 
        addMessage={addMessageToConversation} 
        systemInstruction={systemInstruction}
        isSearchActive={isSearchActive}
        setIsSearchActive={setIsSearchActive}
      />;
    }
    return <WelcomeScreen onNewConversation={handleNewConversation} />;
  };

  return (
    <div className="flex h-screen w-full bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans overflow-hidden">
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <Sidebar conversations={conversations} activeConversationId={activeConversationId} onSelectConversation={handleSelectConversation} onNewConversation={handleNewConversation} isMobileOpen={isMobileSidebarOpen} onClose={() => setIsMobileSidebarOpen(false)} />
      <main className="flex flex-1 flex-col transition-all duration-300 md:pl-64">
        <TopBar user={user} onSignOut={onSignOut} onToggleSidebar={() => setIsMobileSidebarOpen(true)} onShowModal={setActiveModal} onShowSettings={() => setSettingsModalVisible(true)} onSaveConversation={handleSaveConversation} conversationTitle={activeConversation?.title} connectionStatus={connectionStatus} />
        <div className="flex-1 overflow-hidden">{renderContent()}</div>
      </main>
      {isSettingsModalVisible && <SettingsModal settings={personaSettings} onUpdate={setPersonaSettings} onClose={() => setSettingsModalVisible(false)} />}
      {activeModal && <Modal title={activeModal} onClose={() => setActiveModal(null)}>{getModalContent(activeModal)}</Modal>}
    </div>
  );
};

export default ChatApp;

import React, { useEffect, useRef, useState } from 'react';
import type { Conversation, Message } from '../types.ts';
import { MessageBubble } from './MessageBubble.tsx';
import { ChatInput } from './ChatInput.tsx';

interface ChatViewProps {
  conversation: Conversation;
  addMessage: (conversationId: string, message: Message) => void;
  systemInstruction: string;
  isSearchActive: boolean;
  setIsSearchActive: (active: boolean) => void;
}

export const ChatView: React.FC<ChatViewProps> = ({ 
  conversation, 
  addMessage, 
  systemInstruction, 
  isSearchActive, 
  setIsSearchActive 
}) => {
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [conversation.messages]);

  // Check if the last message is from the user to show a loading indicator
  useEffect(() => {
    const lastMessage = conversation.messages[conversation.messages.length - 1];
    if (lastMessage && lastMessage.role === 'user') {
      setIsLoading(true);
    } else {
      setIsLoading(false);
    }
  }, [conversation.messages]);

  const handleSendMessage = async (text: string) => {
    const userMessage: Message = {
      id: `msg-${Date.now()}`,
      role: 'user',
      text,
      timestamp: new Date().toISOString(),
    };
    addMessage(conversation.id, userMessage);
  };

  const handleSendVoiceMessage = (userText: string, aiText: string) => {
    const userTextTrimmed = userText.trim();
    if (userTextTrimmed) {
      const userMessage: Message = {
        id: `msg-${Date.now()}`,
        role: 'user',
        text: userTextTrimmed,
        timestamp: new Date().toISOString(),
      };
      addMessage(conversation.id, userMessage);
    }

    if (aiText.trim()) {
        const aiMessage: Message = {
            id: `msg-${Date.now() + 1}`,
            role: 'model',
            text: aiText.trim(),
            timestamp: new Date().toISOString(),
        };
        addMessage(conversation.id, aiMessage);
    }
  };

  return (
    <div className="h-full flex flex-col bg-gray-100 dark:bg-gray-900 bg-[radial-gradient(ellipse_80%_80%_at_50%_-20%,rgba(37,99,235,0.3),rgba(255,255,255,0))] dark:bg-[radial-gradient(ellipse_80%_80%_at_50%_-20%,rgba(124,58,237,0.3),rgba(255,255,255,0))]">
      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {conversation.messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full opacity-50 text-center px-4">
             <p className="text-lg font-medium">No messages yet.</p>
             <p className="text-sm">Try one of the enhanced prompt presets below!</p>
          </div>
        ) : (
          conversation.messages.map((message) => (
            <MessageBubble key={message.id} message={message} />
          ))
        )}
        {isLoading && (
            <MessageBubble 
                message={{ id: 'loading', role: 'model', text: '...', timestamp: ''}} 
                isLoading={true} 
            />
        )}
        <div ref={messagesEndRef} />
      </div>
      <ChatInput
        onSendMessage={handleSendMessage}
        onSendVoiceMessage={handleSendVoiceMessage}
        isLoading={isLoading}
        systemInstruction={systemInstruction}
        isSearchActive={isSearchActive}
        setIsSearchActive={setIsSearchActive}
      />
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { Mic, Send, Square, Loader2, AlertCircle, Search, Sparkles, BookOpen, Quote, Scissors, HelpCircle } from 'lucide-react';
import { useGeminiLive } from '../hooks/useGeminiLive.ts';
import { GeminiLiveStatus } from '../types.ts';

interface ChatInputProps {
  onSendMessage: (text: string) => void;
  onSendVoiceMessage: (userText: string, aiText: string) => void;
  isLoading: boolean;
  systemInstruction: string;
  isSearchActive: boolean;
  setIsSearchActive: (active: boolean) => void;
}

const MicButton: React.FC<{ status: GeminiLiveStatus; onClick: () => void }> = ({ status, onClick }) => {
    // Helper to determine button styling based on status
    const getButtonContent = () => {
        switch (status) {
            case GeminiLiveStatus.CONNECTING:
                return (
                    <div className="flex items-center justify-center w-11 h-11 rounded-full bg-gray-100 dark:bg-gray-800 border-2 border-brand-blue/30 cursor-wait">
                        <Loader2 size={20} className="text-brand-blue animate-spin" />
                    </div>
                );
            case GeminiLiveStatus.LISTENING:
                return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-red-500 hover:bg-red-600 text-white shadow-[0_0_15px_rgba(239,68,68,0.5)] ring-4 ring-red-500/20 animate-pulse transition-all duration-300"
                        title="Stop Listening"
                    >
                        <Square size={18} className="fill-current" />
                    </button>
                );
            case GeminiLiveStatus.ERROR:
                 return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-red-600 hover:bg-red-700 text-white shadow-lg transition-all duration-300"
                        title="Retry Connection"
                    >
                        <AlertCircle size={20} />
                    </button>
                );
            default: // IDLE
                return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-brand-blue hover:bg-brand-blue/90 text-white shadow-lg shadow-brand-blue/30 hover:scale-105 transition-all duration-300"
                        title="Start Voice Chat"
                    >
                        <Mic size={20} />
                    </button>
                );
        }
    };

    return getButtonContent();
};


export const ChatInput: React.FC<ChatInputProps> = ({ 
  onSendMessage, 
  onSendVoiceMessage, 
  isLoading, 
  systemInstruction,
  isSearchActive,
  setIsSearchActive
}) => {
  const [inputText, setInputText] = useState('');
  const { status, userTranscript, aiTranscript, startSession, stopSession, error } = useGeminiLive();

  useEffect(() => {
    if (status === GeminiLiveStatus.LISTENING) {
      setInputText(userTranscript);
    }
  }, [userTranscript, status]);

  const handleSend = () => {
    if (inputText.trim() && !isLoading) {
      onSendMessage(inputText.trim());
      setInputText('');
    }
  };

  const handleMicToggle = useCallback(() => {
    if (status === GeminiLiveStatus.IDLE || status === GeminiLiveStatus.ERROR) {
      startSession({
        onTurnComplete: (finalUserTranscript, finalAiTranscript) => {
          onSendVoiceMessage(finalUserTranscript, finalAiTranscript);
          setInputText('');
        },
        systemInstruction
      });
    } else {
      stopSession();
    }
  }, [status, startSession, stopSession, onSendVoiceMessage, systemInstruction]);

  const applyPreset = (preset: string) => {
      let finalPrompt = inputText.trim();
      if (!finalPrompt) return;

      switch(preset) {
          case 'summarize':
              finalPrompt = `Please provide a concise summary of the following:\n\n${finalPrompt}`;
              break;
          case 'explain':
              finalPrompt = `Explain this in simple terms that even a non-expert could understand:\n\n${finalPrompt}`;
              break;
          case 'research':
              setIsSearchActive(true);
              finalPrompt = `Perform deep research on this topic using Google Search and provide a detailed verified report:\n\n${finalPrompt}`;
              break;
          case 'procon':
              finalPrompt = `Provide a balanced pro/con list for the following:\n\n${finalPrompt}`;
              break;
      }

      onSendMessage(finalPrompt);
      setInputText('');
  };

  const isInputDisabled = isLoading || status === GeminiLiveStatus.LISTENING || status === GeminiLiveStatus.CONNECTING;

  return (
    <div className="p-4 bg-white/5 dark:bg-gray-800/20 backdrop-blur-lg border-t border-white/10 dark:border-gray-700/50">
        {/* Enhanced Prompt Buttons */}
        <div className="flex items-center gap-2 mb-3 overflow-x-auto pb-1 no-scrollbar max-w-4xl mx-auto">
            <button
                onClick={() => setIsSearchActive(!isSearchActive)}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold transition-all whitespace-nowrap border ${
                    isSearchActive 
                        ? 'bg-brand-blue text-white border-brand-blue shadow-lg shadow-brand-blue/20' 
                        : 'bg-white/10 text-gray-400 border-white/10 hover:border-brand-blue/50'
                }`}
            >
                <Search size={14} />
                Verified Search
            </button>
            <div className="w-px h-4 bg-white/10 mx-1"></div>
            <button
                onClick={() => applyPreset('research')}
                disabled={!inputText.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold bg-white/5 text-gray-400 border border-white/10 hover:border-brand-purple/50 hover:text-brand-purple disabled:opacity-30 whitespace-nowrap transition-all"
            >
                <BookOpen size={14} />
                Deep Research
            </button>
            <button
                onClick={() => applyPreset('summarize')}
                disabled={!inputText.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold bg-white/5 text-gray-400 border border-white/10 hover:border-orange-500/50 hover:text-orange-500 disabled:opacity-30 whitespace-nowrap transition-all"
            >
                <Scissors size={14} />
                Summarize
            </button>
            <button
                onClick={() => applyPreset('explain')}
                disabled={!inputText.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold bg-white/5 text-gray-400 border border-white/10 hover:border-green-500/50 hover:text-green-500 disabled:opacity-30 whitespace-nowrap transition-all"
            >
                <HelpCircle size={14} />
                Explain Simply
            </button>
            <button
                onClick={() => applyPreset('procon')}
                disabled={!inputText.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold bg-white/5 text-gray-400 border border-white/10 hover:border-yellow-500/50 hover:text-yellow-500 disabled:opacity-30 whitespace-nowrap transition-all"
            >
                <Quote size={14} />
                Pro/Con List
            </button>
        </div>

        {error && <div className="mb-2 text-center text-red-500 text-sm animate-fade-in">{error}</div>}

        <div className="flex items-end gap-3 max-w-4xl mx-auto">
            <div className="flex-1 relative">
                <textarea
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    onKeyDown={(e) => {
                        if (e.key === 'Enter' && !e.shiftKey) {
                            e.preventDefault();
                            handleSend();
                        }
                    }}
                    placeholder={status === GeminiLiveStatus.LISTENING ? "Listening..." : (isSearchActive ? "Verified search enabled..." : "Type a message...")}
                    className={`w-full p-3 pr-10 rounded-2xl bg-white dark:bg-gray-700/50 border focus:outline-none focus:ring-2 resize-none min-h-[48px] max-h-32 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm ${
                        isSearchActive 
                        ? 'border-brand-blue focus:ring-brand-blue/30 focus:border-brand-blue' 
                        : 'border-gray-200 dark:border-gray-600 focus:ring-brand-blue/50 focus:border-brand-blue'
                    }`}
                    rows={1}
                    disabled={isInputDisabled}
                />
                {isSearchActive && (
                    <div className="absolute right-3 bottom-3 text-brand-blue animate-pulse">
                        <Search size={16} />
                    </div>
                )}
            </div>

            <MicButton status={status} onClick={handleMicToggle} />

            <button
                onClick={handleSend}
                disabled={!inputText.trim() || isInputDisabled}
                className="flex items-center justify-center w-11 h-11 rounded-full bg-brand-blue text-white hover:bg-brand-blue/90 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200 shadow-lg shadow-brand-blue/20 hover:scale-105"
            >
                {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Send size={20} className="ml-0.5" />}
            </button>
        </div>
        {status === GeminiLiveStatus.LISTENING && aiTranscript && (
             <div className="mt-2 text-center text-xs text-gray-500 dark:text-gray-400 animate-pulse truncate">
                 AI: {aiTranscript}
             </div>
        )}
    </div>
  );
};

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { Sidebar } from './components/Sidebar.tsx';
import { ChatView } from './components/ChatView.tsx';
import { TopBar } from './components/TopBar.tsx';
import { Modal } from './components/Modal.tsx';
import { SettingsModal } from './components/SettingsModal.tsx';
import { ToastContainer, type ToastMessage, type ToastType } from './components/Toast.tsx';
import type { Conversation, Message, User, PersonaSettings, ConnectionStatus, Source } from './types.ts';
import { useLocalStorage } from './hooks/useLocalStorage.ts';
import { WelcomeScreen } from './components/WelcomeScreen.tsx';
import apiService from './services/apiService.ts';
import { websocketService } from './services/websocketService.ts';
import { GoogleGenAI } from "@google/genai";

interface ChatAppProps {
  user: User;
  onSignOut: () => void;
}

const DEFAULT_PERSONA: PersonaSettings = {
    tone: 'friendly',
    verbosity: 'balanced',
    style: 'casual'
};

const ChatApp: React.FC<ChatAppProps> = ({ user, onSignOut }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [personaSettings, setPersonaSettings] = useLocalStorage<PersonaSettings>('easit-persona', DEFAULT_PERSONA);
  const [isSearchActive, setIsSearchActive] = useState(false);

  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [activeModal, setActiveModal] = useState<string | null>(null);
  const [isSettingsModalVisible, setSettingsModalVisible] = useState(false);

  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>('disconnected');

  const addToast = useCallback((message: string, type: ToastType) => {
    const id = Date.now().toString() + Math.random();
    setToasts(prev => [...prev, { id, message, type }]);
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const systemInstruction = useMemo(() => {
      const toneMap: Record<string, string> = {
        friendly: "Be warm, encouraging, and use a conversational tone with occasional emojis.",
        professional: "Be formal, objective, and maintain a respectful distance. Avoid emojis.",
        humorous: "Be witty, playful, and include lighthearted jokes where appropriate.",
        empathetic: "Be understanding, validate the user's feelings, and offer supportive language."
      };

      const verbosityMap: Record<string, string> = {
        concise: "Keep responses extremely brief and directly to the point. No fluff.",
        balanced: "Provide moderate detail, explaining key concepts clearly without over-explaining.",
        detailed: "Provide comprehensive, in-depth responses covering background, examples, and edge cases."
      };

      const styleMap: Record<string, string> = {
        casual: "Use relaxed language, contractions (e.g., 'don't', 'can't'), and simple terms.",
        formal: "Use standard, grammatically rigorous English. Avoid contractions and slang.",
        technical: "Use precise technical terminology. Assume the user is an expert developer."
      };

      return `You are Easit.ai, an intelligent assistant for the SolveEarn community.

      Follow these PERSONA INSTRUCTIONS strictly:
      1. TONE: ${toneMap[personaSettings.tone] || toneMap.friendly}
      2. VERBOSITY: ${verbosityMap[personaSettings.verbosity] || verbosityMap.balanced}
      3. STYLE: ${styleMap[personaSettings.style] || styleMap.casual}

      Always prioritize the user's request while maintaining this persona.`;
  }, [personaSettings]);

  useEffect(() => {
      const handleStatusChange = (status: ConnectionStatus) => {
          setConnectionStatus(status);
      };

      websocketService.addStatusListener(handleStatusChange);
      return () => {
          websocketService.removeStatusListener(handleStatusChange);
      };
  }, []);

  const loadConversations = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
        const storedConversations = await apiService.getConversations();
        setConversations(storedConversations);
    } catch (err: any) {
        console.error("Failed to load conversations:", err);
        setError("Failed to load your conversations.");
        addToast(err.message || "Failed to load conversations", 'error');
    } finally {
        setIsLoading(false);
    }
  }, [addToast]);

  useEffect(() => {
    loadConversations();
  }, [loadConversations]);

  useEffect(() => {
      if (!isLoading && user.email === 'guest@solveearn.com') {
          localStorage.setItem('easit-guest-conversations', JSON.stringify(conversations));
      }
  }, [conversations, user, isLoading]);

  const handleAiMessage = useCallback((data: any) => {
    if (data.type === 'aiMessage') {
        const { conversationId, message } = data.payload;
        setConversations(prev => {
            return prev.map(c => {
                if (c.id === conversationId) {
                    return { ...c, messages: [...c.messages, message] };
                }
                return c;
            });
        });
    } else if (data.type === 'error') {
        addToast(data.payload.message || 'An error occurred', 'error');
    }
  }, [addToast]);

  useEffect(() => {
      websocketService.addMessageListener(handleAiMessage);
      return () => {
          websocketService.removeMessageListener(handleAiMessage);
      };
  }, [handleAiMessage]);


  const activeConversation = useMemo(() => {
    return conversations.find(c => c.id === activeConversationId) || null;
  }, [conversations, activeConversationId]);

  const handleNewConversation = useCallback(() => {
    const newConversation: Conversation = {
      id: `conv-${Date.now()}`,
      title: 'New Chat',
      messages: [],
      createdAt: new Date().toISOString(),
    };
    setConversations(prev => [newConversation, ...prev]);
    setActiveConversationId(newConversation.id);
    setIsMobileSidebarOpen(false);
  }, []);

  const handleSelectConversation = useCallback((id: string) => {
    setActiveConversationId(id);
    setIsMobileSidebarOpen(false);
  }, []);

  const addMessageToConversation = useCallback(async (conversationId: string, message: Message) => {
    setConversations(prev => prev.map(c => {
        if (c.id === conversationId) {
            return { ...c, messages: [...c.messages, message] };
        }
        return c;
    }));

    const token = localStorage.getItem('easit-jwt');
    const isGuest = token && token.includes('guest-demo-token');

    if (isGuest && message.role === 'user') {
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Inclusion of search tool if active
            const config: any = {
                systemInstruction: systemInstruction,
            };
            if (isSearchActive) {
                config.tools = [{ googleSearch: {} }];
            }

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: message.text,
                config: config
            });

            const text = response.text;

            // Extract grounding metadata for hallucination-free verification
            const groundingMetadata: Source[] = [];
            if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
                response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                    if (chunk.web) {
                        groundingMetadata.push({
                            uri: chunk.web.uri,
                            title: chunk.web.title || chunk.web.uri
                        });
                    }
                });
            }

            if (text) {
                 const aiMessage: Message = {
                    id: `ai-${Date.now()}`,
                    role: 'model',
                    text: text,
                    timestamp: new Date().toISOString(),
                    groundingMetadata: groundingMetadata.length > 0 ? groundingMetadata : undefined
                };
                setConversations(prev => prev.map(c => 
                    c.id === conversationId ? { ...c, messages: [...c.messages, aiMessage] } : c
                ));
            }
        } catch (e: any) {
            console.error("Gemini Error", e);
            let errorMessageText = "I'm having trouble connecting right now.";
            addToast("Failed to generate response: " + e.message, 'error');

             const errorMessage: Message = {
                id: `err-${Date.now()}`,
                role: 'model',
                text: errorMessageText,
                timestamp: new Date().toISOString()
            };
             setConversations(prev => prev.map(c => 
                c.id === conversationId ? { ...c, messages: [...c.messages, errorMessage] } : c
            ));
        }
    } else if (!isGuest) {
        try {
            websocketService.sendMessage('chatMessage', { 
                conversationId, 
                userMessage: message, 
                systemInstruction,
                searchEnabled: isSearchActive 
            });
        } catch (e: any) {
             addToast("Connection error: Message not sent.", 'error');
        }
    }
  }, [systemInstruction, addToast, isSearchActive]);

  const handleVerifyMessage = useCallback((conversationId: string, messageToVerify: Message) => {
      const verificationPrompt = `Please perform a "Hallucination Check" on your previous response. Verify the following content against the sources you found: "${messageToVerify.text}". Confirm if all statements are grounded in reality or if any parts were hallucinated.`;

      const userMsg: Message = {
          id: `verify-req-${Date.now()}`,
          role: 'user',
          text: verificationPrompt,
          timestamp: new Date().toISOString()
      };

      addMessageToConversation(conversationId, userMsg);
  }, [addMessageToConversation]);

  const handleSaveConversation = useCallback(() => {
    if (!activeConversation) {
        addToast('No active conversation to save', 'info');
        return;
    }
    try {
        const title = activeConversation.title || 'Conversation';
        const date = new Date(activeConversation.createdAt).toLocaleDateString();
        let content = `Title: ${title}\nDate: ${date}\n\n`;
        activeConversation.messages.forEach(msg => {
            const role = msg.role === 'user' ? 'You' : 'Easit.ai';
            const time = new Date(msg.timestamp).toLocaleTimeString();
            content += `[${time}] ${role}:\n${msg.text}\n\n`;
        });
        const blob = new Blob([content], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${title.replace(/\s+/g, '_').toLowerCase()}_transcript.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        addToast('Conversation saved successfully', 'success');
    } catch (e) {
        addToast('Failed to save conversation', 'error');
    }
  }, [activeConversation, addToast]);

  const getModalContent = (modalTitle: string) => {
      switch (modalTitle.toLowerCase()) {
          case 'about': return <p>Easit.ai is a modern, conversational AI assistant with a sleek interface.</p>;
          case 'privacy': return <p>Your privacy is important. Conversations are now securely stored in your account.</p>;
          case 'contact us': return <p>Contact us at <a href="mailto:support@easit.ai" className="text-brand-blue hover:underline">support@easit.ai</a>.</p>;
          case 'account': return <p>You are signed in as {user.email}.</p>;
          default: return <p>Content not available.</p>;
      }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex items-center justify-center h-full">
          <div className="w-8 h-8 border-4 border-t-transparent border-brand-blue rounded-full animate-spin"></div>
        </div>
      );
    }
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-center p-4">
          <p className="text-red-500 mb-4">{error}</p>
          <button onClick={loadConversations} className="bg-brand-blue text-white px-4 py-2 rounded-lg font-semibold hover:bg-brand-blue/90 transition-colors">Retry</button>
        </div>
      );
    }
    if (activeConversation) {
      return <ChatView 
        key={activeConversation.id} 
        conversation={activeConversation} 
        addMessage={addMessageToConversation} 
        onVerifyMessage={handleVerifyMessage}
        systemInstruction={systemInstruction}
        isSearchActive={isSearchActive}
        setIsSearchActive={setIsSearchActive}
      />;
    }
    return <WelcomeScreen onNewConversation={handleNewConversation} />;
  };

  return (
    <div className="flex h-screen w-full bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans overflow-hidden">
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <Sidebar conversations={conversations} activeConversationId={activeConversationId} onSelectConversation={handleSelectConversation} onNewConversation={handleNewConversation} isMobileOpen={isMobileSidebarOpen} onClose={() => setIsMobileSidebarOpen(false)} />
      <main className="flex flex-1 flex-col transition-all duration-300 md:pl-64">
        <TopBar user={user} onSignOut={onSignOut} onToggleSidebar={() => setIsMobileSidebarOpen(true)} onShowModal={setActiveModal} onShowSettings={() => setSettingsModalVisible(true)} onSaveConversation={handleSaveConversation} conversationTitle={activeConversation?.title} connectionStatus={connectionStatus} />
        <div className="flex-1 overflow-hidden">{renderContent()}</div>
      </main>
      {isSettingsModalVisible && <SettingsModal settings={personaSettings} onUpdate={setPersonaSettings} onClose={() => setSettingsModalVisible(false)} />}
      {activeModal && <Modal title={activeModal} onClose={() => setActiveModal(null)}>{getModalContent(activeModal)}</Modal>}
    </div>
  );
};

export default ChatApp;

import React, { useEffect, useRef, useState } from 'react';
import type { Conversation, Message } from '../types.ts';
import { MessageBubble } from './MessageBubble.tsx';
import { ChatInput } from './ChatInput.tsx';

interface ChatViewProps {
  conversation: Conversation;
  addMessage: (conversationId: string, message: Message) => void;
  onVerifyMessage: (conversationId: string, message: Message) => void;
  systemInstruction: string;
  isSearchActive: boolean;
  setIsSearchActive: (active: boolean) => void;
}

export const ChatView: React.FC<ChatViewProps> = ({ 
  conversation, 
  addMessage, 
  onVerifyMessage,
  systemInstruction, 
  isSearchActive, 
  setIsSearchActive 
}) => {
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [conversation.messages]);

  // Check if the last message is from the user to show a loading indicator
  useEffect(() => {
    const lastMessage = conversation.messages[conversation.messages.length - 1];
    if (lastMessage && lastMessage.role === 'user') {
      setIsLoading(true);
    } else {
      setIsLoading(false);
    }
  }, [conversation.messages]);

  const handleSendMessage = async (text: string) => {
    const userMessage: Message = {
      id: `msg-${Date.now()}`,
      role: 'user',
      text,
      timestamp: new Date().toISOString(),
    };
    addMessage(conversation.id, userMessage);
  };

  const handleSendVoiceMessage = (userText: string, aiText: string) => {
    const userTextTrimmed = userText.trim();
    if (userTextTrimmed) {
      const userMessage: Message = {
        id: `msg-${Date.now()}`,
        role: 'user',
        text: userTextTrimmed,
        timestamp: new Date().toISOString(),
      };
      addMessage(conversation.id, userMessage);
    }

    if (aiText.trim()) {
        const aiMessage: Message = {
            id: `msg-${Date.now() + 1}`,
            role: 'model',
            text: aiText.trim(),
            timestamp: new Date().toISOString(),
        };
        addMessage(conversation.id, aiMessage);
    }
  };

  return (
    <div className="h-full flex flex-col bg-gray-100 dark:bg-gray-900 bg-[radial-gradient(ellipse_80%_80%_at_50%_-20%,rgba(37,99,235,0.3),rgba(255,255,255,0))] dark:bg-[radial-gradient(ellipse_80%_80%_at_50%_-20%,rgba(124,58,237,0.3),rgba(255,255,255,0))]">
      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {conversation.messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full opacity-50 text-center px-4">
             <p className="text-lg font-medium">No messages yet.</p>
             <p className="text-sm">Try one of the enhanced prompt presets below!</p>
          </div>
        ) : (
          conversation.messages.map((message) => (
            <MessageBubble 
              key={message.id} 
              message={message} 
              onVerify={() => onVerifyMessage(conversation.id, message)}
            />
          ))
        )}
        {isLoading && (
            <MessageBubble 
                message={{ id: 'loading', role: 'model', text: '...', timestamp: ''}} 
                isLoading={true} 
            />
        )}
        <div ref={messagesEndRef} />
      </div>
      <ChatInput
        onSendMessage={handleSendMessage}
        onSendVoiceMessage={handleSendVoiceMessage}
        isLoading={isLoading}
        systemInstruction={systemInstruction}
        isSearchActive={isSearchActive}
        setIsSearchActive={setIsSearchActive}
      />
    </div>
  );
};

import React from 'react';
import type { Message } from '../types.ts';
import { User, Sparkles, Link, ShieldCheck } from 'lucide-react';

interface MessageBubbleProps {
  message: Message;
  isLoading?: boolean;
  onVerify?: () => void;
}

const TypingIndicator: React.FC = () => (
    <div className="flex items-center space-x-1.5 h-6 px-2">
        <span className="w-2 h-2 bg-brand-blue/60 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
        <span className="w-2 h-2 bg-brand-purple/60 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
        <span className="w-2 h-2 bg-brand-blue/60 rounded-full animate-bounce"></span>
    </div>
);


export const MessageBubble: React.FC<MessageBubbleProps> = ({ message, isLoading = false, onVerify }) => {
  const isUser = message.role === 'user';
  const hasSources = message.groundingMetadata && message.groundingMetadata.length > 0;

  const bubbleClasses = isUser
    ? 'bg-brand-blue text-white rounded-br-none'
    : 'bg-white/20 dark:bg-gray-700/50 text-gray-800 dark:text-gray-200 rounded-bl-none backdrop-blur-sm shadow-sm';

  const layoutClasses = isUser ? 'justify-end' : 'justify-start';

  const Avatar: React.FC = () => (
    <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${isUser ? 'bg-brand-purple shadow-lg shadow-brand-purple/20' : 'bg-gray-800 border border-white/10'}`}>
      {isUser ? <User size={16} className="text-white"/> : <Sparkles size={16} className="text-brand-blue"/>}
    </div>
  );

  return (
    <div className={`flex items-end gap-3 ${layoutClasses} animate-slide-up-fade-in`}>
      {!isUser && <Avatar />}
      <div className="flex flex-col gap-2 max-w-[85%] md:max-w-xl">
        <div className={`p-4 rounded-2xl relative group ${bubbleClasses}`}>
          {isLoading ? <TypingIndicator /> : <p className="whitespace-pre-wrap leading-relaxed">{message.text}</p>}

          {!isUser && !isLoading && hasSources && (
             <button 
                onClick={onVerify}
                className="absolute -right-12 top-0 p-2 text-gray-400 hover:text-brand-blue transition-colors opacity-0 group-hover:opacity-100"
                title="Verify for Hallucinations"
             >
                <ShieldCheck size={18} />
             </button>
          )}
        </div>

        {hasSources && !isLoading && (
          <div className="animate-fade-in px-1">
            <div className="flex items-center justify-between mb-1">
                <h4 className="text-[10px] uppercase tracking-wider font-bold text-gray-500 dark:text-gray-400">Sources & Verification</h4>
                <button 
                    onClick={onVerify}
                    className="flex items-center gap-1 text-[10px] font-semibold text-brand-blue hover:underline"
                >
                    <ShieldCheck size={10} />
                    Check Hallucinations
                </button>
            </div>
            <div className="flex flex-wrap gap-2">
              {message.groundingMetadata?.map((source, index) => (
                <a
                  key={index}
                  href={source.uri}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex items-center gap-1.5 text-[11px] bg-white/10 dark:bg-gray-800/80 hover:bg-white/20 dark:hover:bg-gray-700 px-2.5 py-1 rounded-full transition-all border border-white/5"
                  title={source.title}
                >
                  <Link size={10} />
                  <span className="truncate max-w-[120px]">{new URL(source.uri).hostname}</span>
                </a>
              ))}
            </div>
          </div>
        )}
      </div>
      {isUser && <Avatar />}
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { Mic, Send, Square, Loader2, AlertCircle, Search, Sparkles, BookOpen, Quote, Scissors, HelpCircle, ShieldCheck } from 'lucide-react';
import { useGeminiLive } from '../hooks/useGeminiLive.ts';
import { GeminiLiveStatus } from '../types.ts';

interface ChatInputProps {
  onSendMessage: (text: string) => void;
  onSendVoiceMessage: (userText: string, aiText: string) => void;
  isLoading: boolean;
  systemInstruction: string;
  isSearchActive: boolean;
  setIsSearchActive: (active: boolean) => void;
}

const MicButton: React.FC<{ status: GeminiLiveStatus; onClick: () => void }> = ({ status, onClick }) => {
    const getButtonContent = () => {
        switch (status) {
            case GeminiLiveStatus.CONNECTING:
                return (
                    <div className="flex items-center justify-center w-11 h-11 rounded-full bg-gray-100 dark:bg-gray-800 border-2 border-brand-blue/30 cursor-wait">
                        <Loader2 size={20} className="text-brand-blue animate-spin" />
                    </div>
                );
            case GeminiLiveStatus.LISTENING:
                return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-red-500 hover:bg-red-600 text-white shadow-[0_0_15px_rgba(239,68,68,0.5)] ring-4 ring-red-500/20 animate-pulse transition-all duration-300"
                        title="Stop Listening"
                    >
                        <Square size={18} className="fill-current" />
                    </button>
                );
            case GeminiLiveStatus.ERROR:
                 return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-red-600 hover:bg-red-700 text-white shadow-lg transition-all duration-300"
                        title="Retry Connection"
                    >
                        <AlertCircle size={20} />
                    </button>
                );
            default: // IDLE
                return (
                    <button
                        onClick={onClick}
                        className="flex items-center justify-center w-11 h-11 rounded-full bg-brand-blue hover:bg-brand-blue/90 text-white shadow-lg shadow-brand-blue/30 hover:scale-105 transition-all duration-300"
                        title="Start Voice Chat"
                    >
                        <Mic size={20} />
                    </button>
                );
        }
    };

    return getButtonContent();
};


export const ChatInput: React.FC<ChatInputProps> = ({ 
  onSendMessage, 
  onSendVoiceMessage, 
  isLoading, 
  systemInstruction,
  isSearchActive,
  setIsSearchActive
}) => {
  const [inputText, setInputText] = useState('');
  const { status, userTranscript, aiTranscript, startSession, stopSession, error } = useGeminiLive();

  useEffect(() => {
    if (status === GeminiLiveStatus.LISTENING) {
      setInputText(userTranscript);
    }
  }, [userTranscript, status]);

  const handleSend = () => {
    if (inputText.trim() && !isLoading) {
      onSendMessage(inputText.trim());
      setInputText('');
    }
  };

  const handleMicToggle = useCallback(() => {
    if (status === GeminiLiveStatus.IDLE || status === GeminiLiveStatus.ERROR) {
      startSession({
        onTurnComplete: (finalUserTranscript, finalAiTranscript) => {
          onSendVoiceMessage(finalUserTranscript, finalAiTranscript);
          setInputText('');
        },
        systemInstruction
      });
    } else {
      stopSession();
    }
  }, [status, startSession, stopSession, onSendVoiceMessage, systemInstruction]);

  const applyPreset = (preset: string) => {
      let finalPrompt = inputText.trim();
      if (!finalPrompt) return;

      switch(preset) {
          case 'summarize':
              finalPrompt = `Please provide a concise summary of the following:\n\n${finalPrompt}`;
              break;
          case 'explain':
              finalPrompt = `Explain this in simple terms that even a non-expert could understand:\n\n${finalPrompt}`;
              break;
          case 'research':
              setIsSearchActive(true);
              finalPrompt = `Perform deep research on this topic using Google Search and provide a detailed verified report:\n\n${finalPrompt}`;
              break;
          case 'procon':
              finalPrompt = `Provide a balanced pro/con list for the following:\n\n${finalPrompt}`;
              break;
          case 'verify':
              finalPrompt = `Verify the following claim for accuracy and potential hallucinations using all available tools:\n\n${finalPrompt}`;
              break;
      }

      onSendMessage(finalPrompt);
      setInputText('');
  };

  const isInputDisabled = isLoading || status === GeminiLiveStatus.LISTENING || status === GeminiLiveStatus.CONNECTING;

  return (
    <div className="p-4 bg-white/5 dark:bg-gray-800/20 backdrop-blur-lg border-t border-white/10 dark:border-gray-700/50">
        <div className="flex items-center gap-2 mb-3 overflow-x-auto pb-1 no-scrollbar max-w-4xl mx-auto">
            <button
                onClick={() => setIsSearchActive(!isSearchActive)}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold uppercase tracking-tight transition-all whitespace-nowrap border ${
                    isSearchActive 
                        ? 'bg-brand-blue text-white border-brand-blue shadow-lg shadow-brand-blue/20' 
                        : 'bg-white/10 text-gray-400 border-white/10 hover:border-brand-blue/50'
                }`}
            >
                <Search size={13} />
                Verified Search
            </button>
            <div className="w-px h-4 bg-white/10 mx-1"></div>
            <button
                onClick={() => applyPreset('research')}
                disabled={!inputText.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold uppercase bg-white/5 text-gray-400 border border-white/10 hover:border-brand-purple/50 hover:text-brand-purple disabled:opacity-30 whitespace-nowrap transition-all"
            >
                <BookOpen size={13} />
                Deep Research
            </button>
            <button
                onClick={() => applyPreset('verify')}
                disabled={!inputText.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold uppercase bg-white/5 text-gray-400 border border-white/10 hover:border-brand-blue/50 hover:text-brand-blue disabled:opacity-30 whitespace-nowrap transition-all"
            >
                <ShieldCheck size={13} />
                Hallucination Check
            </button>
            <button
                onClick={() => applyPreset('summarize')}
                disabled={!inputText.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold uppercase bg-white/5 text-gray-400 border border-white/10 hover:border-orange-500/50 hover:text-orange-500 disabled:opacity-30 whitespace-nowrap transition-all"
            >
                <Scissors size={13} />
                Summarize
            </button>
            <button
                onClick={() => applyPreset('explain')}
                disabled={!inputText.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] font-bold uppercase bg-white/5 text-gray-400 border border-white/10 hover:border-green-500/50 hover:text-green-500 disabled:opacity-30 whitespace-nowrap transition-all"
            >
                <HelpCircle size={13} />
                Explain Simply
            </button>
        </div>

        {error && <div className="mb-2 text-center text-red-500 text-sm animate-fade-in">{error}</div>}

        <div className="flex items-end gap-3 max-w-4xl mx-auto">
            <div className="flex-1 relative">
                <textarea
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    onKeyDown={(e) => {
                        if (e.key === 'Enter' && !e.shiftKey) {
                            e.preventDefault();
                            handleSend();
                        }
                    }}
                    placeholder={status === GeminiLiveStatus.LISTENING ? "Listening..." : (isSearchActive ? "Verified search enabled..." : "Type a message...")}
                    className={`w-full p-3 pr-10 rounded-2xl bg-white dark:bg-gray-700/50 border focus:outline-none focus:ring-2 resize-none min-h-[48px] max-h-32 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm ${
                        isSearchActive 
                        ? 'border-brand-blue focus:ring-brand-blue/30 focus:border-brand-blue' 
                        : 'border-gray-200 dark:border-gray-600 focus:ring-brand-blue/50 focus:border-brand-blue'
                    }`}
                    rows={1}
                    disabled={isInputDisabled}
                />
                {isSearchActive && (
                    <div className="absolute right-3 bottom-3 text-brand-blue animate-pulse">
                        <Search size={16} />
                    </div>
                )}
            </div>

            <MicButton status={status} onClick={handleMicToggle} />

            <button
                onClick={handleSend}
                disabled={!inputText.trim() || isInputDisabled}
                className="flex items-center justify-center w-11 h-11 rounded-full bg-brand-blue text-white hover:bg-brand-blue/90 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200 shadow-lg shadow-brand-blue/20 hover:scale-105"
            >
                {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Send size={20} className="ml-0.5" />}
            </button>
        </div>
        {status === GeminiLiveStatus.LISTENING && aiTranscript && (
             <div className="mt-2 text-center text-xs text-gray-500 dark:text-gray-400 animate-pulse truncate">
                 AI: {aiTranscript}
             </div>
        )}
    </div>
  );
};

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { Sidebar } from './components/Sidebar.tsx';
import { ChatView } from './components/ChatView.tsx';
import { TopBar } from './components/TopBar.tsx';
import { Modal } from './components/Modal.tsx';
import { SettingsModal } from './components/SettingsModal.tsx';
import { ToastContainer, type ToastMessage, type ToastType } from './components/Toast.tsx';
import type { Conversation, Message, User, PersonaSettings, ConnectionStatus, Source } from './types.ts';
import { useLocalStorage } from './hooks/useLocalStorage.ts';
import { WelcomeScreen } from './components/WelcomeScreen.tsx';
import apiService from './services/apiService.ts';
import { websocketService } from './services/websocketService.ts';
import { GoogleGenAI } from "@google/genai";

interface ChatAppProps {
  user: User;
  onSignOut: () => void;
}

const DEFAULT_PERSONA: PersonaSettings = {
    tone: 'friendly',
    verbosity: 'balanced',
    style: 'casual'
};

const ChatApp: React.FC<ChatAppProps> = ({ user, onSignOut }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [personaSettings, setPersonaSettings] = useLocalStorage<PersonaSettings>('easit-persona', DEFAULT_PERSONA);
  const [isSearchActive, setIsSearchActive] = useState(false);

  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [activeModal, setActiveModal] = useState<string | null>(null);
  const [isSettingsModalVisible, setSettingsModalVisible] = useState(false);

  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>('disconnected');

  const addToast = useCallback((message: string, type: ToastType) => {
    const id = Date.now().toString() + Math.random();
    setToasts(prev => [...prev, { id, message, type }]);
  }, []);

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const systemInstruction = useMemo(() => {
      const toneMap: Record<string, string> = {
        friendly: "Be warm, encouraging, and use a conversational tone with occasional emojis.",
        professional: "Be formal, objective, and maintain a respectful distance. Avoid emojis.",
        humorous: "Be witty, playful, and include lighthearted jokes where appropriate.",
        empathetic: "Be understanding, validate the user's feelings, and offer supportive language."
      };

      const verbosityMap: Record<string, string> = {
        concise: "Keep responses extremely brief and directly to the point. No fluff.",
        balanced: "Provide moderate detail, explaining key concepts clearly without over-explaining.",
        detailed: "Provide comprehensive, in-depth responses covering background, examples, and edge cases."
      };

      const styleMap: Record<string, string> = {
        casual: "Use relaxed language, contractions (e.g., 'don't', 'can't'), and simple terms.",
        formal: "Use standard, grammatically rigorous English. Avoid contractions and slang.",
        technical: "Use precise technical terminology. Assume the user is an expert developer."
      };

      return `You are Easit.ai, an intelligent assistant for the SolveEarn community.

      Follow these PERSONA INSTRUCTIONS strictly:
      1. TONE: ${toneMap[personaSettings.tone] || toneMap.friendly}
      2. VERBOSITY: ${verbosityMap[personaSettings.verbosity] || verbosityMap.balanced}
      3. STYLE: ${styleMap[personaSettings.style] || styleMap.casual}

      Always prioritize the user's request while maintaining this persona.`;
  }, [personaSettings]);

  useEffect(() => {
      const handleStatusChange = (status: ConnectionStatus) => {
          setConnectionStatus(status);
      };

      websocketService.addStatusListener(handleStatusChange);
      return () => {
          websocketService.removeStatusListener(handleStatusChange);
      };
  }, []);

  const loadConversations = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
        const storedConversations = await apiService.getConversations();
        setConversations(storedConversations);
    } catch (err: any) {
        console.error("Failed to load conversations:", err);
        setError("Failed to load your conversations.");
        addToast(err.message || "Failed to load conversations", 'error');
    } finally {
        setIsLoading(false);
    }
  }, [addToast]);

  useEffect(() => {
    loadConversations();
  }, [loadConversations]);

  useEffect(() => {
      if (!isLoading && user.email === 'guest@solveearn.com') {
          localStorage.setItem('easit-guest-conversations', JSON.stringify(conversations));
      }
  }, [conversations, user, isLoading]);

  const handleAiMessage = useCallback((data: any) => {
    if (data.type === 'aiMessage') {
        const { conversationId, message } = data.payload;
        setConversations(prev => {
            return prev.map(c => {
                if (c.id === conversationId) {
                    return { ...c, messages: [...c.messages, message] };
                }
                return c;
            });
        });
    } else if (data.type === 'error') {
        addToast(data.payload.message || 'An error occurred', 'error');
    }
  }, [addToast]);

  useEffect(() => {
      websocketService.addMessageListener(handleAiMessage);
      return () => {
          websocketService.removeMessageListener(handleAiMessage);
      };
  }, [handleAiMessage]);


  const activeConversation = useMemo(() => {
    return conversations.find(c => c.id === activeConversationId) || null;
  }, [conversations, activeConversationId]);

  const handleNewConversation = useCallback(() => {
    const newConversation: Conversation = {
      id: `conv-${Date.now()}`,
      title: 'New Chat',
      messages: [],
      createdAt: new Date().toISOString(),
    };
    setConversations(prev => [newConversation, ...prev]);
    setActiveConversationId(newConversation.id);
    setIsMobileSidebarOpen(false);
  }, []);

  const handleSelectConversation = useCallback((id: string) => {
    setActiveConversationId(id);
    setIsMobileSidebarOpen(false);
  }, []);

  const addMessageToConversation = useCallback(async (conversationId: string, message: Message) => {
    setConversations(prev => prev.map(c => {
        if (c.id === conversationId) {
            return { ...c, messages: [...c.messages, message] };
        }
        return c;
    }));

    const token = localStorage.getItem('easit-jwt');
    const isGuest = token && token.includes('guest-demo-token');

    if (isGuest && message.role === 'user') {
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Inclusion of search tool if active
            const config: any = {
                systemInstruction: systemInstruction,
            };
            if (isSearchActive) {
                config.tools = [{ googleSearch: {} }];
            }

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: message.text,
                config: config
            });

            const text = response.text;

            // Extract grounding metadata for hallucination-free verification
            const groundingMetadata: Source[] = [];
            if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
                response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
                    if (chunk.web) {
                        groundingMetadata.push({
                            uri: chunk.web.uri,
                            title: chunk.web.title || chunk.web.uri
                        });
                    }
                });
            }

            if (text) {
                 const aiMessage: Message = {
                    id: `ai-${Date.now()}`,
                    role: 'model',
                    text: text,
                    timestamp: new Date().toISOString(),
                    groundingMetadata: groundingMetadata.length > 0 ? groundingMetadata : undefined
                };
                setConversations(prev => prev.map(c => 
                    c.id === conversationId ? { ...c, messages: [...c.messages, aiMessage] } : c
                ));
            }
        } catch (e: any) {
            console.error("Gemini Error", e);
            let errorMessageText = "I'm having trouble connecting right now.";
            addToast("Failed to generate response: " + e.message, 'error');

             const errorMessage: Message = {
                id: `err-${Date.now()}`,
                role: 'model',
                text: errorMessageText,
                timestamp: new Date().toISOString()
            };
             setConversations(prev => prev.map(c => 
                c.id === conversationId ? { ...c, messages: [...c.messages, errorMessage] } : c
            ));
        }
    } else if (!isGuest) {
        try {
            websocketService.sendMessage('chatMessage', { 
                conversationId, 
                userMessage: message, 
                systemInstruction,
                searchEnabled: isSearchActive 
            });
        } catch (e: any) {
             addToast("Connection error: Message not sent.", 'error');
        }
    }
  }, [systemInstruction, addToast, isSearchActive]);

  const handleVerifyMessage = useCallback((conversationId: string, messageToVerify: Message) => {
      const verificationPrompt = `Please perform a "Hallucination Check" on your previous response. Verify the following content against the sources you found: "${messageToVerify.text}". Confirm if all statements are grounded in reality or if any parts were hallucinated.`;

      const userMsg: Message = {
          id: `verify-req-${Date.now()}`,
          role: 'user',
          text: verificationPrompt,
          timestamp: new Date().toISOString()
      };

      addMessageToConversation(conversationId, userMsg);
  }, [addMessageToConversation]);

  const handleSaveConversation = useCallback(() => {
    if (!activeConversation) {
        addToast('No active conversation to save', 'info');
        return;
    }
    try {
        const title = activeConversation.title || 'Conversation';
        const date = new Date(activeConversation.createdAt).toLocaleDateString();
        let content = `Title: ${title}\nDate: ${date}\n\n`;
        activeConversation.messages.forEach(msg => {
            const role = msg.role === 'user' ? 'You' : 'Easit.ai';
            const time = new Date(msg.timestamp).toLocaleTimeString();
            content += `[${time}] ${role}:\n${msg.text}\n\n`;
        });
        const blob = new Blob([content], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${title.replace(/\s+/g, '_').toLowerCase()}_transcript.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        addToast('Conversation saved successfully', 'success');
    } catch (e) {
        addToast('Failed to save conversation', 'error');
    }
  }, [activeConversation, addToast]);

  const getModalContent = (modalTitle: string) => {
      switch (modalTitle.toLowerCase()) {
          case 'about': return <p>Easit.ai is a modern, conversational AI assistant with a sleek interface.</p>;
          case 'privacy': return <p>Your privacy is important. Conversations are now securely stored in your account.</p>;
          case 'contact us': return <p>Contact us at <a href="mailto:support@easit.ai" className="text-brand-blue hover:underline">support@easit.ai</a>.</p>;
          case 'account': return <p>You are signed in as {user.email}.</p>;
          default: return <p>Content not available.</p>;
      }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex items-center justify-center h-full">
          <div className="w-8 h-8 border-4 border-t-transparent border-brand-blue rounded-full animate-spin"></div>
        </div>
      );
    }
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-center p-4">
          <p className="text-red-500 mb-4">{error}</p>
          <button onClick={loadConversations} className="bg-brand-blue text-white px-4 py-2 rounded-lg font-semibold hover:bg-brand-blue/90 transition-colors">Retry</button>
        </div>
      );
    }
    if (activeConversation) {
      return <ChatView 
        key={activeConversation.id} 
        conversation={activeConversation} 
        addMessage={addMessageToConversation} 
        onVerifyMessage={handleVerifyMessage}
        systemInstruction={systemInstruction}
        isSearchActive={isSearchActive}
        setIsSearchActive={setIsSearchActive}
      />;
    }
    return <WelcomeScreen onNewConversation={handleNewConversation} />;
  };

  return (
    <div className="flex h-screen w-full bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans overflow-hidden">
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <Sidebar conversations={conversations} activeConversationId={activeConversationId} onSelectConversation={handleSelectConversation} onNewConversation={handleNewConversation} isMobileOpen={isMobileSidebarOpen} onClose={() => setIsMobileSidebarOpen(false)} />
      <main className="flex flex-1 flex-col transition-all duration-300 md:pl-64">
        <TopBar 
          user={user} 
          onSignOut={onSignOut} 
          onToggleSidebar={() => setIsMobileSidebarOpen(true)} 
          onNewConversation={handleNewConversation}
          onShowModal={setActiveModal} 
          onShowSettings={() => setSettingsModalVisible(true)} 
          onSaveConversation={handleSaveConversation} 
          conversationTitle={activeConversation?.title} 
          connectionStatus={connectionStatus} 
        />
        <div className="flex-1 overflow-hidden">{renderContent()}</div>
      </main>
      {isSettingsModalVisible && <SettingsModal settings={personaSettings} onUpdate={setPersonaSettings} onClose={() => setSettingsModalVisible(false)} />}
      {activeModal && <Modal title={activeModal} onClose={() => setActiveModal(null)}>{getModalContent(activeModal)}</Modal>}
    </div>
  );
};

export default ChatApp;

import React, { useState, useRef, useEffect } from 'react';
import { Sun, Moon, PanelLeft, LogOut, User as UserIcon, Settings, Info, Shield, Mail, Sliders, WifiOff, RefreshCw, Save, MessageSquarePlus } from 'lucide-react';
import { useTheme } from '../hooks/useTheme.ts';
import type { User, ConnectionStatus } from '../types.ts';

interface TopBarProps {
    user: User;
    onSignOut: () => void;
    onToggleSidebar: () => void;
    onNewConversation: () => void;
    onShowModal: (modal: string) => void;
    onShowSettings: () => void;
    onSaveConversation: () => void;
    conversationTitle?: string;
    connectionStatus: ConnectionStatus;
}

const UserMenu: React.FC<{ user: User; onSignOut: () => void; onShowModal: (modal: string) => void; onShowSettings: () => void; }> = ({ user, onSignOut, onShowModal, onShowSettings }) => {
    const [isOpen, setIsOpen] = useState(false);
    const menuRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const menuItems = [
        { label: 'Customize Persona', icon: Sliders, onClick: () => onShowSettings() },
        { label: 'Account', icon: Settings, onClick: () => onShowModal('Account') },
        { label: 'About', icon: Info, onClick: () => onShowModal('About') },
        { label: 'Privacy', icon: Shield, onClick: () => onShowModal('Privacy') },
        { label: 'Contact Us', icon: Mail, onClick: () => onShowModal('Contact Us') },
    ];

    return (
        <div className="relative" ref={menuRef}>
            <button onClick={() => setIsOpen(!isOpen)} className="w-9 h-9 rounded-full focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-blue focus:ring-offset-gray-800">
                {user.picture ? (
                    <img src={user.picture} alt="User" className="w-full h-full rounded-full" />
                ) : (
                    <div className="w-full h-full rounded-full bg-brand-purple flex items-center justify-center">
                        <UserIcon size={20} className="text-white" />
                    </div>
                )}
            </button>
            {isOpen && (
                <div className="absolute right-0 mt-2 w-64 bg-white dark:bg-gray-800 rounded-md shadow-lg py-1 z-20 border border-white/10 dark:border-gray-700/50">
                    <div className="px-4 py-2 border-b border-gray-200 dark:border-gray-700">
                        <p className="text-sm font-semibold text-gray-800 dark:text-white truncate">{user.name}</p>
                        <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{user.email}</p>
                    </div>
                    <div className="py-1">
                        {menuItems.map((item, index) => (
                             <button
                                key={index}
                                onClick={() => { item.onClick(); setIsOpen(false); }}
                                className="w-full text-left flex items-center gap-3 px-4 py-2 text-sm text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-700"
                            >
                                <item.icon size={16} />
                                {item.label}
                            </button>
                        ))}
                    </div>
                    <div className="py-1 border-t border-gray-200 dark:border-gray-700">
                         <button
                            onClick={onSignOut}
                            className="w-full text-left flex items-center gap-3 px-4 py-2 text-sm text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-500/10"
                        >
                            <LogOut size={16} />
                            Sign Out
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

const ConnectionBadge: React.FC<{ status: ConnectionStatus }> = ({ status }) => {
    if (status === 'connected') return null;

    if (status === 'reconnecting') {
        return (
            <div className="flex items-center gap-1.5 px-2 py-1 bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400 text-xs rounded-full animate-pulse">
                <RefreshCw size={12} className="animate-spin" />
                <span className="hidden md:inline">Reconnecting...</span>
            </div>
        );
    }

    if (status === 'disconnected') {
        return (
            <div className="flex items-center gap-1.5 px-2 py-1 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 text-xs rounded-full">
                <WifiOff size={12} />
                <span className="hidden md:inline">Offline</span>
            </div>
        );
    }

    return null;
};


